def get_locale(value):
    return value if value in LOCALES else "en"


def get_copy(locale):
    return CONTENT[get_locale(locale)]


def localized(instance, field, locale):
    value = getattr(instance, f"{field}_{locale}", "") or getattr(instance, f"{field}_en", "")
    return value or ""


def language_links(current):
    return [
        {
            "code": locale,
            "label": LOCALE_LABELS[locale],
            "flag": LOCALE_FLAGS[locale],
            "active": locale == current,
            "url": f"/{locale}/",
        }
        for locale in LOCALES
    ]


