def get_admin_copy(locale):
    return ADMIN_COPY[get_locale(locale)]


def admin_language_links(current, current_path):
    return [
        {
            "code": locale,
            "label": LOCALE_LABELS[locale],
            "flag": LOCALE_FLAGS[locale],
            "active": locale == current,
            "url": f"{current_path}?lang={locale}",
        }
        for locale in LOCALES
    ]
